const results = [];

for (const item of $input.all()) {
  // --- IMPORTANTE ---
  // Asumimos que el MIME type está en esta ruta.
  // ¡Verifica que 'item.json.data.mimetype' es correcto para tus datos!
  // Podría ser 'item.json.mimetype' o similar.
  const mimetype = $('Descargar Media').first().json.data.mimetype || '';

  let fileTypeCategory = 'other'; // Valor por defecto para tipos no reconocidos

  // Usamos switch(true) para evaluar diferentes condiciones basadas en el mimetype
  switch (true) {
    // === Imágenes ===
    case mimetype.startsWith('image/'):
      fileTypeCategory = 'image';
      break;

    // === Audio ===
    // Incluye mp3 ('audio/mpeg'), ogg, wav, etc.
    case mimetype.startsWith('audio/'):
      fileTypeCategory = 'audio';
      break;

    // === Video ===
    // Incluye mp4, webm, mov ('video/quicktime'), etc.
    case mimetype.startsWith('video/'):
      fileTypeCategory = 'video';
      break;

    // === Documentos de Texto y Ofimática ===
    case mimetype === 'application/pdf':
      fileTypeCategory = 'pdf';
      break;

    // Spreadsheets (Excel, ODS, etc.)
    case mimetype === 'application/vnd.ms-excel':
    case mimetype === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet':
    case mimetype === 'application/vnd.oasis.opendocument.spreadsheet':
      fileTypeCategory = 'spreadsheet';
      break;

    // Word Documents
    case mimetype === 'application/msword':
    case mimetype === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document':
      fileTypeCategory = 'document';
      break;

    // Archivos de texto plano (txt, md, log)
    case mimetype === 'text/plain':
      fileTypeCategory = 'text';
      break;

    case mimetype === 'text/csv':
      fileTypeCategory = 'csv';
      break;

    case mimetype === 'text/html':
      fileTypeCategory = 'html';
      break;

    case mimetype === 'application/rtf':
      fileTypeCategory = 'rtf';
      break;

    // === Datos Estructurados ===
    case mimetype === 'application/json':
      fileTypeCategory = 'json';
      break;

    case mimetype === 'application/xml':
    case mimetype === 'text/xml':
      fileTypeCategory = 'xml';
      break;

    // === Otros ===
    case mimetype === 'text/calendar': // para .ics
      fileTypeCategory = 'ics';
      break;
  }

  // Añadimos la nueva propiedad 'fileTypeCategory' al objeto json del item
  item.json.fileTypeCategory = fileTypeCategory;

  // Añadimos el item modificado al array de resultados
  results.push(item);
}

// Devolvemos el array con todos los items modificados
return results;

const error = $input.first().json;

const workflowName = error.workflow?.name || 'Desconocido';
const nodeName = error.execution?.lastNodeExecuted || 'Desconocido';
const errorMessage = error.execution?.error?.message || 'Error desconocido';
const number = error.execution?.data?.resultData?.runData?.['Global Variables']?.[0]?.data?.main?.[0]?.[0]?.json?.number || null;

return [{ json: { workflowName, nodeName, errorMessage, number } }];

